const r = $('Code - Normalize Quote Result').first().json;

// -------------------------
// SAFE DATA
// -------------------------
const lineItems = Array.isArray(r.line_items) ? r.line_items : [];
const alternatives = Array.isArray(r.provider_alternatives) ? r.provider_alternatives : [];

// -------------------------
// TABLE RENDERERS
// -------------------------
const rowHtml = (rows) =>
	rows.map((item) => `
	<tr>
		<td style="padding:10px;border-bottom:1px solid #e6d8b4;">
			${String(item.label ?? item.provider ?? '-')}
		</td>
		<td style="padding:10px;border-bottom:1px solid #e6d8b4;">
			${String(item.percentage ?? item.city ?? '-')}
			${item.percentage != null ? '%' : ''}
		</td>
		<td style="padding:10px;border-bottom:1px solid #e6d8b4;">
			${String(item.amount ?? item.avg_price ?? item.fit_score ?? '-')}
		</td>
	</tr>`).join('');

// -------------------------
const lineItemsTable = lineItems.length
	? `<table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;margin-top:12px;">
		<thead>
			<tr>
				<th align="left" style="padding:10px;border-bottom:2px solid #c9a34e;">Line Item</th>
				<th align="left" style="padding:10px;border-bottom:2px solid #c9a34e;">%</th>
				<th align="left" style="padding:10px;border-bottom:2px solid #c9a34e;">Amount</th>
			</tr>
		</thead>
		<tbody>${rowHtml(lineItems)}</tbody>
	</table>`
	: '<p>No line items available.</p>';

// -------------------------
const altRows = alternatives.length
	? `<table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;margin-top:12px;">
		<thead>
			<tr>
				<th align="left" style="padding:10px;border-bottom:2px solid #c9a34e;">Provider</th>
				<th align="left" style="padding:10px;border-bottom:2px solid #c9a34e;">City</th>
				<th align="left" style="padding:10px;border-bottom:2px solid #c9a34e;">Avg Price</th>
				<th align="left" style="padding:10px;border-bottom:2px solid #c9a34e;">Fit Score</th>
			</tr>
		</thead>
		<tbody>
			${alternatives.map((item) => `
				<tr>
					<td style="padding:10px;border-bottom:1px solid #e6d8b4;">${String(item.provider ?? '-')}</td>
					<td style="padding:10px;border-bottom:1px solid #e6d8b4;">${String(item.city ?? '-')}</td>
					<td style="padding:10px;border-bottom:1px solid #e6d8b4;">${String(item.avg_price ?? '-')}</td>
					<td style="padding:10px;border-bottom:1px solid #e6d8b4;">${Number(item.fit_score ?? 0).toFixed(2)}%</td>
				</tr>
			`).join('')}
		</tbody>
	</table>`
	: '<p>No provider alternatives available.</p>';

// -------------------------
// SAFE SUMMARY (FIX IMPORTANT 🔥)
// -------------------------
const summarySafe = String(r.llm_summary || '')
	.replace(/\n/g, '<br>')
	.replace(/</g, '&lt;')
	.replace(/>/g, '&gt;');

// -------------------------
// SUBJECT
// -------------------------
const subject = `Intelligent Quote - ${r.client_name || 'Client'} - ${r.quote_id || ''}`.trim();

// -------------------------
// HTML EMAIL
// -------------------------
const html = `
<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>${subject}</title>
</head>

<body style="margin:0;padding:0;background:#f6f1e3;font-family:Arial,sans-serif;color:#1f1a0b;">

<div style="max-width:760px;margin:0 auto;padding:24px;">

	<!-- HEADER -->
	<div style="background:linear-gradient(135deg,#1f1a0b,#5b4611);color:#fff;padding:22px;border-radius:18px 18px 0 0;">
		<h1 style="margin:0;font-size:24px;">Intelligent Quote</h1>
		<p style="margin:8px 0 0;opacity:.95;">Prepared for ${r.client_name || 'Client'}</p>
	</div>

	<!-- BODY -->
	<div style="background:#fff;padding:22px;border:1px solid #e6d8b4;border-top:none;border-radius:0 0 18px 18px;">

		<p style="font-size:16px;line-height:1.6;margin-top:0;">
			Hello ${r.client_name || 'Client'},
		</p>

		<!-- SUMMARY BOX -->
		<table width="100%" cellpadding="0" cellspacing="0" style="margin:18px 0;border-collapse:collapse;">
			<tr>
				<td style="padding:12px;background:#f8f4ea;border:1px solid #e6d8b4;">
					<strong>Total Quote</strong><br>${Number(r.total_quote || 0).toFixed(2)}
				</td>
				<td style="padding:12px;background:#f8f4ea;border:1px solid #e6d8b4;">
					<strong>Base Cost</strong><br>${Number(r.base_estimated_cost || 0).toFixed(2)}
				</td>
				<td style="padding:12px;background:#f8f4ea;border:1px solid #e6d8b4;">
					<strong>Margin</strong><br>${Number(r.target_margin_percent || 0).toFixed(2)}%
				</td>
			</tr>
		</table>

		<h2 style="font-size:18px;margin:22px 0 10px;">Quote Breakdown</h2>
		${lineItemsTable}

		<h2 style="font-size:18px;margin:22px 0 10px;">Provider Alternatives</h2>
		${altRows}

		<h2 style="font-size:18px;margin:22px 0 10px;">AI Summary</h2>
		<div style="background:#faf7ef;border-left:4px solid #c9a34e;padding:16px;border-radius:10px;line-height:1.7;">
			${summarySafe}
		</div>

		${r.notes
			? `<p style="margin-top:18px;color:#6f5a24;"><strong>Notes:</strong> ${String(r.notes)}</p>`
			: ''}

		<p style="margin-top:24px;color:#6f5a24;font-size:13px;">
			Generated by Eventzella Intelligent Quote Generator.
		</p>

	</div>
</div>

</body>
</html>
`;

// -------------------------
return [{
	json: {
		...r,
		email_subject: subject,
		email_html: html
	}
}];
